-- Name: llamado_concurso_historial_view; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.llamado_concurso_historial_view AS
 SELECT llc.id,
    llc.rif_organoente,
    llc.numero_proceso,
    llc.id_modalidad,
    llc.id_mecanismo,
    llc.id_objeto_contratacion,
    llc.dias_habiles,
    llc.fecha_llamado,
    llc.fecha_disponible_llamado,
    llc.fecha_fin_aclaratoria,
    llc.fecha_tope,
    llc.fecha_fin_llamado,
    llc.denominacion_proceso,
    llc.descripcion_contratacion,
    llc.web_contratante,
    llc.hora_desde,
    llc.hora_hasta,
    llc.id_estado,
    llc.id_municipio,
    llc.direccion,
    llc.hora_desde_sobre,
    llc.id_estado_sobre,
    llc.id_municipio_sobre,
    llc.direccion_sobre,
    llc.lugar_entrega,
    llc.observaciones,
    llc.especifique_anulacion,
    llc.id_usuario,
    llc.fecha_cam_estatus,
    llc.fecha45dias,
    llc.articulo,
    llc.estatus AS idestatus,
    llc.fecha_inicio_aclaratoria,
    mcn.descripcion AS mecanismo,
    mdl.descripcion AS modalidad,
    obc.descripcion AS objeto_contratacion,
    est.descedo AS estado,
    mpio.descmun AS municipio,
    oe.descripcion AS organoente,
    oe.siglas,
    ests.descedo AS estado_sobre,
    mpios.descmun AS municipio_sobre,
    sta.id_llcestatus,
    sta.descripcion AS estatus
   FROM (((((((((public.historico_llamado_concurso llc
     JOIN public.estados est ON ((llc.id_estado = est.id)))
     JOIN public.mecanismo mcn ON ((llc.id_mecanismo = mcn.id_mecanismo)))
     JOIN public.modalidad mdl ON ((llc.id_modalidad = mdl.id_modalidad)))
     JOIN public.municipios mpio ON ((llc.id_municipio = mpio.id)))
     JOIN public.objeto_contratacion obc ON ((llc.id_objeto_contratacion = obc.id_objeto_contratacion)))
     JOIN public.organoente oe ON (((llc.rif_organoente)::text = (oe.rif)::text)))
     JOIN public.estados ests ON ((llc.id_estado_sobre = ests.id)))
     JOIN public.municipios mpios ON ((llc.id_municipio_sobre = mpios.id)))
     JOIN public.llcestatus sta ON ((llc.estatus = sta.id_llcestatus)));


ALTER VIEW public.llamado_concurso_historial_view OWNER TO postgres;

